import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.util.UriComponentsBuilder;

import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import java.io.IOException;
import java.security.SecureRandom;
import java.util.Base64;

@SpringBootApplication
public class OAuth2ClientApplication {
    public static void main(String[] args) {
        SpringApplication.run(OAuth2ClientApplication.class, args);
    }
}

@Configuration
@EnableWebSecurity
class SecurityConfig {
    
    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
            .authorizeHttpRequests(auth -> auth
                .requestMatchers("/", "/login", "/oauth2/callback").permitAll()
                .anyRequest().authenticated()
            )
            .csrf(csrf -> csrf.ignoringRequestMatchers("/oauth2/callback"));
        
        return http.build();
    }
}

@Controller
class OAuth2Controller {
    
    private static final String AUTHORIZATION_ENDPOINT = "https://authorization-server.example.com/oauth/authorize";
    private static final String CLIENT_ID = "your-client-id";
    private static final String REDIRECT_URI = "http://localhost:8080/oauth2/callback";
    private static final String SCOPE = "read write";
    private static final String RESPONSE_TYPE = "code";
    
    private final SecureRandom secureRandom = new SecureRandom();
    
    @GetMapping("/")
    public String home() {
        return "index";
    }
    
    @GetMapping("/login")
    public void login(HttpServletResponse response, HttpSession session) throws IOException {
        String state = generateState();
        session.setAttribute("oauth_state", state);
        
        String authorizationUrl = UriComponentsBuilder
            .fromHttpUrl(AUTHORIZATION_ENDPOINT)
            .queryParam("client_id", CLIENT_ID)
            .queryParam("redirect_uri", REDIRECT_URI)
            .queryParam("scope", SCOPE)
            .queryParam("response_type", RESPONSE_TYPE)
            .queryParam("state", state)
            .build()
            .toUriString();
        
        response.sendRedirect(authorizationUrl);
    }
    
    @GetMapping("/oauth2/callback")
    public String callback(String code, String state, HttpSession session, HttpServletResponse response) throws IOException {
        String sessionState = (String) session.getAttribute("oauth_state");
        
        if (sessionState == null || !sessionState.equals(state)) {
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid state parameter - possible CSRF attack");
            return null;
        }
        
        session.removeAttribute("oauth_state");
        
        if (code == null || code.isEmpty()) {
            return "error";
        }
        
        return "success";
    }
    
    private String generateState() {
        byte[] randomBytes = new byte[32];
        secureRandom.nextBytes(randomBytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(randomBytes);
    }
}